import{_ as t,o,c as s,ag as a}from"./chunks/framework.CanvC6-R.js";const u=JSON.parse('{"title":"Module System","description":"","frontmatter":{},"headers":[],"relativePath":"language/module_system.md","filePath":"language/module_system.md"}'),r={name:"language/module_system.md"};function i(n,e,d,l,c,h){return o(),s("div",null,[...e[0]||(e[0]=[a('<h1 id="module-system" tabindex="-1">Module System <a class="header-anchor" href="#module-system" aria-label="Permalink to &quot;Module System&quot;">​</a></h1><p>The module system is how Bliss code is organized and shared across files and packages. Bliss provides two distinct keywords for bringing code into scope: <code>import</code> and <code>use</code>.</p><h2 id="the-distinction" tabindex="-1">The Distinction <a class="header-anchor" href="#the-distinction" aria-label="Permalink to &quot;The Distinction&quot;">​</a></h2><p>While both keywords bring code into scope, they serve fundamentally different purposes:</p><ul><li><code>import</code> reaches <strong>outward</strong> — it brings in code from an external package.</li><li><code>use</code> reaches <strong>inward</strong> — it brings in code from within the current project.</li></ul><p>This distinction is intentional. At any point in a Bliss file, it is immediately clear whether a dependency is external or internal based solely on the keyword used.</p><h2 id="scope-rules" tabindex="-1">Scope Rules <a class="header-anchor" href="#scope-rules" aria-label="Permalink to &quot;Scope Rules&quot;">​</a></h2><p>Both <code>import</code> and <code>use</code> follow the same scoping rule — the <strong>last segment</strong> of the path is what enters scope. This applies consistently regardless of how deep the path is.</p><h2 id="what-s-covered" tabindex="-1">What&#39;s Covered <a class="header-anchor" href="#what-s-covered" aria-label="Permalink to &quot;What&#39;s Covered&quot;">​</a></h2><p><strong>Import</strong> — how external packages are brought into a Bliss project.</p><p><strong>Use</strong> — how files within the current project are brought into scope, and how the project root governs all paths.</p>',11)])])}const m=t(r,[["render",i]]);export{u as __pageData,m as default};
